const rows = $input.all().map(i => i.json);
const sentAts = rows.map(r => new Date(r.sent_at)).filter(d => !isNaN(d.getTime()));
const minSent = sentAts.length ? new Date(Math.min(...sentAts.map(d => d.getTime()))) : new Date(Date.now() - 60*60*1000);
const SLACK_MS = 5 * 60 * 1000;
const startDate = new Date(minSent.getTime() - SLACK_MS).toISOString();
const endDate = new Date(Date.now() + SLACK_MS).toISOString();
return { json: { startDate, endDate, rows } };

// Build map: postiz_id -> { state, publishDate, releaseURL }
const resp = $input.first().json;
const posts = (resp && resp.posts) || [];
const byId = new Map();
for (const p of posts) byId.set(p.id, p);

const STUCK_THRESHOLD_SECONDS = 30 * 60;
const KNOWN_STATES = new Set(['PUBLISHED', 'QUEUE', 'ERROR']);

const rows = $('Compute Window Bounds').item.json.rows || [];
const out = [];
for (const r of rows) {
  const post = byId.get(r.postiz_post_id);
  if (!post) {
    out.push({ json: { publish_job_id: r.publish_job_id, outreach_item_id: r.outreach_item_id, postiz_post_id: r.postiz_post_id, action: 'FAIL_ORPHAN', payload: {} } });
    continue;
  }
  if (!KNOWN_STATES.has(post.state)) {
    out.push({ json: { publish_job_id: r.publish_job_id, outreach_item_id: r.outreach_item_id, postiz_post_id: r.postiz_post_id, action: 'WARN_UNKNOWN', payload: { state: post.state } } });
    continue;
  }
  if (post.state === 'PUBLISHED') {
    out.push({ json: { publish_job_id: r.publish_job_id, outreach_item_id: r.outreach_item_id, postiz_post_id: r.postiz_post_id, action: 'PUBLISH', payload: { publish_date: post.publishDate, release_url: post.releaseURL || '' } } });
    continue;
  }
  if (post.state === 'ERROR') {
    out.push({ json: { publish_job_id: r.publish_job_id, outreach_item_id: r.outreach_item_id, postiz_post_id: r.postiz_post_id, action: 'FAIL_ERROR', payload: {} } });
    continue;
  }
  // QUEUE
  if (Number(r.age_seconds) >= STUCK_THRESHOLD_SECONDS) {
    out.push({ json: { publish_job_id: r.publish_job_id, outreach_item_id: r.outreach_item_id, postiz_post_id: r.postiz_post_id, action: 'STUCK', payload: { age_seconds: Number(r.age_seconds) } } });
  } else {
    out.push({ json: { publish_job_id: r.publish_job_id, outreach_item_id: r.outreach_item_id, postiz_post_id: r.postiz_post_id, action: 'NOOP', payload: {} } });
  }
}
return out;
